package org.apache.commons.math3.optimization.direct;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.optimization.direct.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.optimization.direct.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.*;
import org.apache.commons.math3.analysis.MultivariateFunction;
import org.apache.commons.math3.exception.NumberIsTooLargeException;
import org.apache.commons.math3.optimization.GoalType;
import org.apache.commons.math3.optimization.direct.CMAESOptimizer;
import org.apache.commons.math3.optimization.PointValuePair;

public class StepDefs {

    private CMAESOptimizer optimizer;
    private MultivariateFunction function;
    private double[] startPoint;
    private double[] lowerBound;
    private double[] upperBound;
    private PointValuePair result;
    private boolean exceptionThrown = false;

    @Given("the CMAES optimizer is initialized")
    public void the_cmaes_optimizer_is_initialized() {
        // Initialize the CMAES optimizer
        optimizer = new CMAESOptimizer();
    }

    @Given("a quadratic fitness function defined as f\\\\(x\\\\) = \\\\({double} \\\\- x\\\\)\\\\^2")
    public void a_quadratic_fitness_function_defined_as_f_x_11_1_x_2(double targetValue) {
        // Define the quadratic fitness function f(x) = (11.1 - x)^2
        function = new MultivariateFunction() {
            @Override
            public double value(double[] point) {
                return Math.pow(targetValue - point[0], 2);
            }
        };
    }

    @Given("the lower bound is set to -5e16")
    public void the_lower_bound_is_set_to_minus_5e16() {
        lowerBound = new double[]{-5e16};
    }

    @Given("the upper bound is set to 20")
    public void the_upper_bound_is_set_to_20() {
        upperBound = new double[]{20};
    }

    @Given("the start point is {double}")
    public void the_start_point_is(double startPointValue) {
        startPoint = new double[]{startPointValue};
    }

    @When("minimizing the function with the CMAES optimizer")
    public void minimizing_the_function_with_the_cmaes_optimizer() {
        try {
            result = optimizer.optimize(
                10000, // max evaluations
                function,
                GoalType.MINIMIZE,
                startPoint,
                lowerBound,
                upperBound
            );
        } catch (Exception e) {
            exceptionThrown = true;
        }
    }

    @Then("the result should be approximately {double} within {double} tolerance")
    public void the_result_should_be_approximately_within_tolerance(double expected, double tolerance) {
        if (exceptionThrown) {
            fail("Exception was thrown during optimization: NumberIsTooLargeException");
        } else {
            assertNotNull("Optimization result should not be null", result);
            double actual = result.getPoint()[0];
            assertEquals("Optimization result should be approximately " + expected, expected, actual, tolerance);
        }
    }
}

